#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100005
#define MOD 1000000007

// Adjacency list
int head[MAXN], to[2 * MAXN], next_edge[2 * MAXN];
int visited[MAXN];
int edge_count;

void addEdge(int u, int v) {
    to[edge_count] = v;
    next_edge[edge_count] = head[u];
    head[u] = edge_count++;
}

int dfs(int start) {
    int stack[MAXN];
    int top = 0;
    stack[top++] = start;
    visited[start] = 1;
    int size = 1;

    while (top > 0) {
        int u = stack[--top];

        for (int e = head[u]; e != -1; e = next_edge[e]) {
            int v = to[e];
            if (!visited[v]) {
                visited[v] = 1;
                stack[top++] = v;
                size++;
            }
        }
    }
    return size;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);

        // Initialize
        for (int i = 1; i <= N; i++) {
            head[i] = -1;
            visited[i] = 0;
        }
        edge_count = 0;

        // Read friendships
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(u, v);
            addEdge(v, u);
        }

        int components = 0;
        long long ways = 1;

        for (int i = 1; i <= N; i++) {
            if (!visited[i]) {
                int size = dfs(i);
                components++;
                ways = (ways * size) % MOD;
            }
        }

        printf("%d %lld\n", components, ways);
    }

    return 0;
}

